### 7. Pinia Store设计

```typescript
// stores/log.ts
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { api } from '@/services/api'

export interface Log {
  id: number
  level: 'DEBUG' | 'INFO' | 'WARN' | 'ERROR'
  agent: string
  message: string
  timestamp: number
  iterationId?: number
}

export const useLogStore = defineStore('log', () => {
  const logs = ref<Log[]>([])
  const loading = ref(false)
  const stats = ref({
    total: 0,
    byLevel: {} as Record<string, number>,
    byAgent: {} as Record<string, number>
  })

  // 过滤日志
  const filteredLogs = computed(() => (filters: any) => {
    return logs.value.filter(log => {
      if (filters.level !== 'ALL' && log.level !== filters.level) return false
      if (filters.agent !== 'ALL' && log.agent !== filters.agent) return false
      if (filters.search && !log.message.includes(filters.search)) return false
      return true
    })
  })

  // 添加新日志
  function addLog(log: Log) {
    logs.value.unshift(log)
    updateStats(log)
  }

  // 更新统计
  function updateStats(log: Log) {
    stats.value.total++
    stats.value.byLevel[log.level] = (stats.value.byLevel[log.level] || 0) + 1
    stats.value.byAgent[log.agent] = (stats.value.byAgent[log.agent] || 0) + 1
  }

  // 获取历史日志
  async function fetchLogs(params?: any) {
    loading.value = true
    try {
      const response = await api.get('/api/logs', { params })
      logs.value = response.data.logs
      stats.value = response.data.stats
    } finally {
      loading.value = false
    }
  }

  // 清除日志
  async function clearLogs() {
    await api.delete('/api/logs')
    logs.value = []
    stats.value = { total: 0, byLevel: {}, byAgent: {} }
  }

  // 导出日志
  function exportLogs(format: 'json' | 'csv' = 'json') {
    const data = format === 'json' 
      ? JSON.stringify(logs.value, null, 2)
      : convertToCSV(logs.value)

    const blob = new Blob([data], { type: 'text/plain' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `logs-${Date.now()}.${format}`
    a.click()
  }

  return {
    logs,
    loading,
    stats,
    filteredLogs,
    addLog,
    fetchLogs,
    clearLogs,
    exportLogs
  }
})
```

